// // This module is a 4-bit binary counter with asynchronous reset and disable functionality.
module binary_counter(
    input        clk,
    input        rst,
    input        en,
    output reg [3:0] q
);

always @(posedge clk) begin
    if (rst) 
        q <= 4'b0000;
    else if (en)
        q <= q + 1;
end

endmodule
